## Common patterns

### Appointment scheduler

A pattern for scheduling appointments with date and time selection:

```jsx-live-dev
import { CalendarDateTime, type DateValue } from '@internationalized/date';

const App = () => {
  const [appointmentTime, setAppointmentTime] = useState<DateValue | null>(
    new CalendarDateTime(2025, 12, 15, 10, 0, 0)
  );

  const businessHoursStart = 9;
  const businessHoursEnd = 17;

  const isInvalidTime = appointmentTime && 
    'hour' in appointmentTime && (
      appointmentTime.hour < businessHoursStart || 
      appointmentTime.hour >= businessHoursEnd
    );

  return (
    <FormField.Root isInvalid={isInvalidTime}>
      <FormField.Label>Appointment Time</FormField.Label>
      <FormField.Input>
        <DatePicker
          value={appointmentTime}
          onChange={setAppointmentTime}
          granularity="minute"
          hourCycle={12}
          aria-label="Appointment time"
        />
      </FormField.Input>
      <FormField.Description>
        Select a date and time between 9:00 AM and 5:00 PM
      </FormField.Description>
      {isInvalidTime && (
        <FormField.Error>
          Please select a time during business hours (9 AM - 5 PM)
        </FormField.Error>
      )}
      {appointmentTime && !isInvalidTime && (
        <Text fontSize="sm" mt="200">
          ✅ Appointment scheduled for {appointmentTime.toString()}
        </Text>
      )}
    </FormField.Root>
  );
}
```

### Due date selector

Pattern for setting due dates with past date validation:

```jsx-live-dev
import { CalendarDate, today, getLocalTimeZone, type DateValue } from '@internationalized/date';

const App = () => {
  const [dueDate, setDueDate] = useState<DateValue | null>(null);
  const todayDate = today(getLocalTimeZone());

  const isInvalid = dueDate && dueDate.compare(todayDate) < 0;

  return (
    <FormField.Root isInvalid={!!isInvalid}>
      <FormField.Label>Task Due Date</FormField.Label>
      <FormField.Input>
        <DatePicker
          value={dueDate}
          onChange={setDueDate}
          minValue={todayDate}
          placeholderValue={todayDate}
          aria-label="Due date"
        />
      </FormField.Input>
      <FormField.Description>
        Select a future date for task completion
      </FormField.Description>
      {isInvalid && (
        <FormField.Error>
          Due date cannot be in the past
        </FormField.Error>
      )}
    </FormField.Root>
  );
}
```

### Event date selector

Pattern for selecting event dates with a reasonable range:

```jsx-live-dev
import { CalendarDate, today, getLocalTimeZone, type DateValue } from '@internationalized/date';

const App = () => {
  const [eventDate, setEventDate] = useState<DateValue | null>(null);
  const todayDate = today(getLocalTimeZone());
  const maxDate = todayDate.add({ years: 2 });

  return (
    <FormField.Root>
      <FormField.Label>Event Date</FormField.Label>
      <FormField.Input>
        <DatePicker
          value={eventDate}
          onChange={setEventDate}
          minValue={todayDate}
          maxValue={maxDate}
          placeholderValue={todayDate.add({ months: 1 })}
          aria-label="Event date"
        />
      </FormField.Input>
      <FormField.Description>
        Select a date within the next 2 years
      </FormField.Description>
      {eventDate && (
        <Text fontSize="sm" mt="200">
          Event scheduled for {eventDate.toString()}
        </Text>
      )}
    </FormField.Root>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using DatePicker within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the DatePicker renders with expected elements and structure

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, within, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { DatePicker, NimbusProvider } from "@commercetools/nimbus";
import { CalendarDate, CalendarDateTime } from "@internationalized/date";

describe("DatePicker - Basic rendering", () => {
  it("renders with proper structure and accessibility", () => {
    render(
      <NimbusProvider>
        <DatePicker aria-label="Select a date" />
      </NimbusProvider>
    );

    const dateGroup = screen.getByRole("group", { name: "Select a date" });
    expect(dateGroup).toBeInTheDocument();
    expect(dateGroup).toHaveAttribute("aria-label", "Select a date");
  });

  it("renders date input segments", () => {
    render(
      <NimbusProvider>
        <DatePicker aria-label="Select a date" />
      </NimbusProvider>
    );

    const dateSegments = screen.getAllByRole("spinbutton");
    expect(dateSegments.length).toBeGreaterThanOrEqual(3);
  });

  it("renders calendar toggle button", () => {
    render(
      <NimbusProvider>
        <DatePicker aria-label="Select a date" />
      </NimbusProvider>
    );

    const calendarButton = screen.getByRole("button", { name: /calendar/i });
    expect(calendarButton).toBeInTheDocument();
  });

  it("renders with default value", () => {
    const defaultValue = new CalendarDate(2025, 6, 15);

    render(
      <NimbusProvider>
        <DatePicker defaultValue={defaultValue} aria-label="Select a date" />
      </NimbusProvider>
    );

    const dateSegments = screen.getAllByRole("spinbutton");
    expect(dateSegments[0]).toHaveAttribute("aria-valuenow", "6");
    expect(dateSegments[1]).toHaveAttribute("aria-valuenow", "15");
    expect(dateSegments[2]).toHaveAttribute("aria-valuenow", "2025");
  });
});
```

### Interaction Tests

Test user interactions with date segments and calendar

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, within, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { DatePicker, NimbusProvider } from "@commercetools/nimbus";
import { CalendarDate, CalendarDateTime } from "@internationalized/date";

describe("DatePicker - Interactions", () => {
  it("allows keyboard input in date segments", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <DatePicker aria-label="Select a date" />
      </NimbusProvider>
    );

    const dateSegments = screen.getAllByRole("spinbutton");
    const firstSegment = dateSegments[0];

    await user.click(firstSegment);
    await user.keyboard("12");

    await waitFor(() => {
      expect(firstSegment).toHaveAttribute("aria-valuenow", "12");
    });
  });

  it("opens calendar popover when button is clicked", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <DatePicker aria-label="Select a date" />
      </NimbusProvider>
    );

    const calendarButton = screen.getByRole("button", { name: /calendar/i });

    expect(
      within(document.body).queryByRole("application")
    ).not.toBeInTheDocument();

    await user.click(calendarButton);

    await waitFor(() => {
      expect(
        within(document.body).queryByRole("application")
      ).toBeInTheDocument();
    });
  });

  it("closes calendar popover with Escape key", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <DatePicker aria-label="Select a date" />
      </NimbusProvider>
    );

    const calendarButton = screen.getByRole("button", { name: /calendar/i });
    await user.click(calendarButton);

    await waitFor(() => {
      expect(
        within(document.body).queryByRole("application")
      ).toBeInTheDocument();
    });

    await user.keyboard("{Escape}");

    await waitFor(() => {
      expect(
        within(document.body).queryByRole("application")
      ).not.toBeInTheDocument();
    });
  });

  it("allows date selection from calendar", async () => {
    const user = userEvent.setup();
    const onChange = vi.fn();

    render(
      <NimbusProvider>
        <DatePicker onChange={onChange} aria-label="Select a date" />
      </NimbusProvider>
    );

    const calendarButton = screen.getByRole("button", { name: /calendar/i });
    await user.click(calendarButton);

    await waitFor(() => {
      expect(
        within(document.body).queryByRole("application")
      ).toBeInTheDocument();
    });

    const day5Cell = document.body.querySelector('[aria-label*="5,"]');
    if (day5Cell) {
      await user.click(day5Cell);

      await waitFor(() => {
        expect(onChange).toHaveBeenCalled();
      });
    }
  });

  it("navigates between segments with Tab key", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <DatePicker aria-label="Select a date" />
      </NimbusProvider>
    );

    const dateSegments = screen.getAllByRole("spinbutton");

    await user.tab();

    await waitFor(() => {
      expect(dateSegments[0]).toHaveFocus();
    });

    await user.keyboard("{ArrowRight}");

    if (dateSegments.length > 1) {
      await waitFor(() => {
        expect(dateSegments[1]).toHaveFocus();
      });
    }
  });
});
